    limit #{offset}, #{pageSize}

select count(1)
from tb_stock_record


        and id = #{query.id}


        and material_id = #{query.materialId}


        and change_type = #{query.changeType}


        and change_num = #{query.changeNum}


        and before_stock = #{query.beforeStock}


        and after_stock = #{query.afterStock}


        and use_person = #{query.usePerson}


