        and create_time = #{query.createTime}

SELECT r.*, m.material_name, m.unit FROM tb_stock_record r LEFT JOIN tb_material m ON r.material_id = m.id
DATE(r.create_time) >= #{dto.startTime}
DATE(r.create_time) <= #{dto.endTime}
m.material_name LIKE CONCAT('%',#{dto.materialName},'%')
r.change_type = #{dto.changeType}
r.use_person LIKE CONCAT('%',#{dto.usePerson},'%')
ORDER BY r.create_time DESC
